#include <bits/stdc++.h>
using namespace std;

const int N=3e5+5;

struct Edge{
    int to,val;
}f[N][21];

struct Node{
    int u,v,w,lca;
}qu[N],edge[N];

bool cmp(Node x,Node y){
    return x.w<y.w;
}

int n,m,dfn[N],num,dep[N],siz[N],c[N];
vector<Edge> g[N];

void dfs(int x,int fa){
    dep[x]=dep[fa]+1;
    dfn[x]=++num,siz[x]=1;
    for(Edge y:g[x])
        if(y.to!=fa){
            f[y.to][0]={x,y.val};
            for(int i=1;f[f[y.to][i-1].to][i-1].to;i++){
                f[y.to][i].to=f[f[y.to][i-1].to][i-1].to;
                f[y.to][i].val=f[y.to][i-1].val+f[f[y.to][i-1].to][i-1].val;
            }
            dfs(y.to,x);
            siz[x]+=siz[y.to];
        }
}

Edge LCA(int x,int y){
    if(dep[x]<dep[y])
        swap(x,y);
    int res=0;
    for(int i=20;i>=0;i--)
        if(dep[f[x][i].to]>=dep[y])
            res+=f[x][i].val,x=f[x][i].to;
    if(x==y)
        return {x,res};
    for(int i=20;i>=0;i--)
        if(f[x][i].to!=f[y][i].to){
            res+=f[x][i].val+f[y][i].val;
            x=f[x][i].to,y=f[y][i].to;
        }
    res+=f[x][0].val+f[y][0].val;
    return {f[x][0].to,res};
}

void add(int x,int k){
    for(;x<=n;x+=(x&(-x)))
        c[x]+=k;
}

bool check(int len){
    for(int i=1;i<=n;i++)
        c[i]=0;
    int l=0;
    for(int i=1;i<=m;i++){
        if(qu[i].w<=len)
            continue;
        if(!l)
        	l=i;
        int top=qu[i].lca;
        add(dfn[qu[i].u],1),add(dfn[qu[i].v],1);
        add(dfn[top],-1);
        if(top>1)
            add(dfn[f[top][0].to],-1);
    }
    int res=0;
    for(int i=1;i<=n;i++)
        c[i]+=c[i-(i&(-i))];
    for(int i=1;i<n;i++){
        int x=c[dfn[edge[i].u]+siz[edge[i].u]-1]-c[dfn[edge[i].u]-1];
        int y=c[dfn[edge[i].v]+siz[edge[i].v]-1]-c[dfn[edge[i].v]-1];
        if(x==m-l+1 && y==m-l+1)
            res=max(res,edge[i].w);
    }
    return qu[m].w-res<=len;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,u,v,w;i<n;i++){
        scanf("%d%d%d",&u,&v,&w);
        g[u].push_back({v,w});
        g[v].push_back({u,w});
        edge[i]={u,v,w};
    }
    dfs(1,0);
    for(int i=1;i<=m;i++){
        scanf("%d%d",&qu[i].u,&qu[i].v);
        Edge tmp=LCA(qu[i].u,qu[i].v);
        qu[i].w=tmp.val;
        qu[i].lca=tmp.to;
    }
    sort(qu+1,qu+m+1,cmp);
    int l=0,r=qu[m].w;
    while(l<r){
        int mid=l+r>>1;
        if(check(mid))
            r=mid;
        else
            l=mid+1;
    }
    printf("%d",l);
    return 0;
}
